import React, { useState,useEffect } from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";

function WeeklyReport(){
     const [nutritions,setNutritions]=useState([]);
     const [report,setReport]=useState({
        weekly_report:[],
        total_carbs:0,
        total_calories:0,
        total_exercise:0,
        status:{
            carbsStatus:"",
            calorieStatus:"",
            exerciseStatus:""
        },
        recommendations:[]
     });
    const navigate=useNavigate();

    async function handlePage() {
        
        try{
            const response=await fetch('http://localhost:5000/weeklyreport');
            const data=await response.json();
            console.log(data);
            setNutritions(data.weekly_report);
            setReport(data);
            
        }
        catch(err){
            console.log(err.message);
        }
        
    }

    function gotoDashboard(){
        navigate('/dashboard');
    }

    useEffect(()=>{handlePage()},[]);

    return(
        <>
            <div>
                {nutritions.map((item,index)=>
                    <h2 key={index}>Date:{item.day} {"  |  "}  Carbs:{item.total_carbs} {"  |  "} Calories:{item.total_calories}</h2>
                )}
            </div>
           
           <table border="1">
                <tr>
                    <th>Date</th>
                    <th>Carbs</th>
                    <th>Calories</th>
                </tr>
                {nutritions.map((item,index)=>
                    <tr key={index}>
                        <td>{item.day}</td>
                        <td>{item.total_carbs}</td>
                        <td>{item.total_calories}</td>
                    </tr>
                )}
           </table>
            
            <h1>Carbs Status={report.status?.carbsStatus}</h1>
            <h3 style={{textAlign:"center"}}>{report.recommendations[0]}</h3>
            <h1>Calorie Status={report.status?.calorieStatus}</h1>
            <h3 style={{textAlign:"center"}}>{report.recommendations[1]}</h3>
            <h1>Exercise Status={report.status?.exerciseStatus}</h1>
            <h3 style={{textAlign:"center"}}>{report.recommendations[2]}</h3>
            <button onClick={gotoDashboard}>Go To Dashboard</button>
        </>
    );
}

export default WeeklyReport;
